import app.k9mail.core.android.testing.RobolectricTest
import com.fsck.k9.mail.Address
import org.junit.Test
import org.mockito.kotlin.mock

class MessageHelperRecipientDisplayTest : RobolectricTest() {

    private val resourceProvider = TestCoreResourceProvider()
    private val contactRepository = mock<app.k9mail.core.android.common.contact.ContactRepository>()
    private val messageHelper = MessageHelper(resourceProvider, contactRepository)

    @Test
    fun `getRecipientDisplayNames should add space between prefix and recipient`() {
        val addresses = arrayOf(Address("test@example.com", "Test User"))
        val result = messageHelper.getRecipientDisplayNames(addresses)

        // Verify there's a space between "To:" and the address
        assertThat(result.toString()).isEqualTo("To: Test User")
    }

    @Test
    fun `getRecipientDisplayNames with single recipient`() {
        val addresses = arrayOf(Address("alice@example.com", "Alice"))
        val result = messageHelper.getRecipientDisplayNames(addresses)

        assertThat(result.toString()).isEqualTo("To: Alice")
    }

    @Test
    fun `getRecipientDisplayNames with multiple recipients`() {
        val addresses = arrayOf(
            Address("alice@example.com", "Alice"),
            Address("bob@example.com", "Bob")
        )
        val result = messageHelper.getRecipientDisplayNames(addresses)

        // Verify space after "To:" and recipients are separated by comma without additional spaces
        assertThat(result.toString()).isEqualTo("To: Alice,Bob")
    }

    @Test
    fun `getRecipientDisplayNames with null addresses`() {
        val result = messageHelper.getRecipientDisplayNames(null)

        assertThat(result.toString()).isEqualTo("Unknown")
    }

    @Test
    fun `getRecipientDisplayNames with empty addresses`() {
        val result = messageHelper.getRecipientDisplayNames(emptyArray())

        assertThat(result.toString()).isEqualTo("Unknown")
    }
}"}

