190→    fun deleteAccount(account: Account) {
191→        synchronized(accountLock) {
192→            accountsMap?.remove(account.uuid)
193→            accountsInOrder.remove(account)
194→
195→            val storageEditor = createStorageEditor()
196→            accountPreferenceSerializer.delete(storageEditor, storage, account)
197→            storageEditor.commit()
198→
199→            if (account === newAccount) {
200→                newAccount = null
201→            }
202→        }
203→
204→        notifyAccountRemovedListeners(account)
205→        notifyAccountsChangeListeners()
206→    }
207→
208→    val defaultAccount: Account?
209→        get() = getAccounts().firstOrNull()
210→
211→    override fun saveAccount(account: Account) {
212→        ensureAssignedAccountNumber(account)
213→        processChangedValues(account)
214→
215→        synchronized(accountLock) {
216→            val editor = createStorageEditor()
217→            accountPreferenceSerializer.save(editor, storage, account)
218→            editor.commit()
219→        }
220→
221→        notifyAccountsChangeListeners()
222→    }
