 */
class Settings {
    /**
     * Version number of global and account settings.
     *
     * <p>
     * This value is used as "version" attribute in the export file. It needs to be incremented
     * when a global or account setting is added or removed, or when the format of a setting
     * is changed (e.g. add a value to an enum).
     * </p>
     *
     * @see SettingsExporter
     */
    public static final int VERSION = 101;

    static Map<String, Object> validate(int version, Map<String, TreeMap<Integer, SettingsDescription<?>>> settings,
            Map<String, String> importedSettings, boolean useDefaultValues) {

        Map<String, Object> validatedSettings = new HashMap<>();
        for (Map.Entry<String, TreeMap<Integer, SettingsDescription<?>>> versionedSetting : settings.entrySet()) {

            // Get the setting description with the highest version lower than or equal to the
            // supplied content version.
            TreeMap<Integer, SettingsDescription<?>> versions = versionedSetting.getValue();
            SortedMap<Integer, SettingsDescription<?>> headMap = versions.headMap(version + 1);

            // Skip this setting if it was introduced after 'version'
            if (headMap.isEmpty()) {
                continue;
            }

            // Get the setting description for 'version'
            Map.Entry<Integer, SettingsDescription<?>> entry = headMap.lastEntry();
            SettingsDescription<?> description = entry.getValue();

            // Skip this setting if it was removed after 'version'
            if (description == null) {
                continue;
            }

            String key = versionedSetting.getKey();
            String valueString = importedSettings.get(key);

            if (valueString == null) {
                if (useDefaultValues) {
                    validatedSettings.put(key, description.getDefaultValue());
                }
            } else {
                try {
                    Object value = description.fromString(valueString);
                    validatedSettings.put(key, value);
                } catch (InvalidSettingValueException e) {
                    Timber.w("Value for setting '%s' is invalid. Using default value.", key);
                    if (useDefaultValues) {
                        validatedSettings.put(key, description.getDefaultValue());
                    }
                }
            }
        }

        return validatedSettings;
    }

    static <T> Map<String, String> convert(Map<String, T> settings) {
        Map<String, String> output = new HashMap<>();

        for (Map.Entry<String, T> entry : settings.entrySet()) {
            String key = entry.getKey();
            T value = entry.getValue();
            output.put(key, value.toString());
        }

        return Collections.unmodifiableMap(output);
    }

    static void insertDefaultValues(
            Map<String, TreeMap<Integer, SettingsDescription<?>>> settingsDescriptions,
            Map<String, Object> settings) {
        for (Map.Entry<String, TreeMap<Integer, SettingsDescription<?>>> entry : settingsDescriptions.entrySet()) {
            String key = entry.getKey();
            TreeMap<Integer, SettingsDescription<?>> versions = entry.getValue();
            SettingsDescription<?> description = versions.get(versions.lastKey());

            if (description != null && !settings.containsKey(key)) {
                settings.put(key, description.getDefaultValue());
            }
        }
    }

    static <V> TreeMap<Integer, V> versions(V... values) {
        TreeMap<Integer, V> map = new TreeMap<>();
        for (int i = 0; i < values.length; i++) {
            map.put(i + 1, values[i]);
        }
        return map;
    }

    static class InvalidSettingValueException extends Exception {
        public InvalidSettingValueException() {
            super();
        }

        public InvalidSettingValueException(String message) {
            super(message);
        }
    }

    static class V {
        int version;
        SettingsDescription<?> setting;

        V(int version, SettingsDescription<?> setting) {
            this.version = version;
            this.setting = setting;
        }
    }

    static abstract class SettingsDescription<T> {
        private T defaultValue;

        SettingsDescription(T defaultValue) {
            this.defaultValue = defaultValue;
        }

        public T getDefaultValue() {
            return defaultValue;
        }

        public abstract T fromString(String value) throws InvalidSettingValueException;

        public String toPrettyString(T value) {
            return value.toString();
        }
    }

    static class BooleanSetting extends SettingsDescription<Boolean> {
        BooleanSetting(boolean defaultValue) {
            super(defaultValue);
        }

        @Override
        public Boolean fromString(String value) throws InvalidSettingValueException {
            if ("true".equalsIgnoreCase(value) || "1".equals(value)) {
                return true;
            } else if ("false".equalsIgnoreCase(value) || "0".equals(value)) {
                return false;
            }
            throw new InvalidSettingValueException();
        }
    }

    static class StringSetting extends SettingsDescription<String> {
        StringSetting(String defaultValue) {
            super(defaultValue);
        }

        @Override
        public String fromString(String value) throws InvalidSettingValueException {
            return value;
        }
    }

    static class IntegerSetting extends SettingsDescription<Integer> {
        private int min;
        private int max;

        IntegerSetting(int defaultValue, int min, int max) {
            super(defaultValue);
            this.min = min;
            this.max = max;
        }

        @Override
        public Integer fromString(String value) throws InvalidSettingValueException {
            try {
                int intValue = Integer.parseInt(value);
                if (intValue >= min && intValue <= max) {
                    return intValue;
                }
                throw new InvalidSettingValueException();
            } catch (NumberFormatException e) {
                throw new InvalidSettingValueException();
            }
        }
    }

    static class EnumSetting<T extends Enum<T>> extends SettingsDescription<T> {
        private Class<T> enumClass;

        EnumSetting(Class<T> enumClass, T defaultValue) {
            super(defaultValue);
            this.enumClass = enumClass;
        }

        @Override
        public T fromString(String value) throws InvalidSettingValueException {
            try {
                return Enum.valueOf(enumClass, value);
            } catch (Exception e) {
                throw new InvalidSettingValueException();
            }
        }
    }
}"}

