 3→import android.content.Context
 4→import android.content.Intent
 5→import android.os.Bundle
 6→import androidx.activity.enableEdgeToEdge
 7→import app.k9mail.core.ui.compose.common.activity.setActivityContent
 8→import app.k9mail.feature.launcher.ui.FeatureLauncherApp
 9→import com.fsck.k9.ui.base.K9Activity
10→
11→class FeatureLauncherActivity : K9Activity() {
12→
13→    override fun onCreate(savedInstanceState: Bundle?) {
14→        super.onCreate(savedInstanceState)
15→
16→        enableEdgeToEdge()
17→
18→        setActivityContent {
19→            FeatureLauncherApp()
20→        }
21→    }
22→
23→    companion object {
24→        @JvmStatic
25→        fun launch(context: Context, target: FeatureLauncherTarget) {
26→            val intent = getIntent(context, target)
27→            context.startActivity(intent)
28→        }
29→
30→        @JvmStatic
31→        fun getIntent(context: Context, target: FeatureLauncherTarget): Intent {
32→            return Intent(context, FeatureLauncherActivity::class.java).apply {
33→                data = target.deepLinkUri
34→                if (target.flags != null) {
35→                    flags = target.flags
36→                }
37→            }
38→        }
39→    }
40→}
