{"file_path":"/project/feature/launcher/src/main/kotlin/app/k9mail/feature/launcher/FeatureLauncherActivity.kt","content":"package app.k9mail.feature.launcher

import android.content.Context
import android.content.Intent
import android.os.Bundle
import androidx.activity.enableEdgeToEdge
import androidx.activity.compose.setContent
import app.k9mail.feature.launcher.ui.FeatureLauncherApp
import com.fsck.k9.ui.base.K9Activity

class FeatureLauncherActivity : K9Activity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        enableEdgeToEdge()

        setContent {
            FeatureLauncherApp()
        }
    }

    companion object {
        @JvmStatic
        fun launch(context: Context, target: FeatureLauncherTarget) {
            val intent = getIntent(context, target)
            context.startActivity(intent)
        }

        @JvmStatic
        fun getIntent(context: Context, target: FeatureLauncherTarget): Intent {
            return Intent(context, FeatureLauncherActivity::class.java).apply {
                data = target.deepLinkUri
                if (target.flags != null) {
                    flags = target.flags
                }
            }
        }
    }
}"}

{"file_path":"/project/feature/funding/googleplay/src/main/kotlin/app/k9mail/feature/funding/googleplay/ui/contribution/ContributionScreen.kt","content":"package app.k9mail.feature.funding.googleplay.ui.contribution

import android.content.Intent
import android.net.Uri
import androidx.activity.compose.BackHandler
import androidx.activity.compose.LocalActivity
import androidx.compose.runtime.Composable
import androidx.compose.ui.Modifier
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.res.stringResource
import app.k9mail.core.ui.compose.common.mvi.observe
import app.k9mail.core.ui.compose.designsystem.organism.TopAppBarWithBackButton
import app.k9mail.core.ui.compose.designsystem.template.Scaffold
import app.k9mail.feature.funding.googleplay.R
import app.k9mail.feature.funding.googleplay.ui.contribution.ContributionContract.ViewModel
import org.koin.androidx.compose.koinViewModel

@Composable
internal fun ContributionScreen(
    onBack: () -> Unit,
    modifier: Modifier = Modifier,
    viewModel: ViewModel = koinViewModel<ContributionViewModel>(),
) {
    val activity = LocalActivity.current
    val context = LocalContext.current

    val (state, dispatch) = viewModel.observe { effect ->
        when (effect) {
            is ContributionContract.Effect.ManageSubscription -> {
                context.startActivity(
                    getManageSubscriptionIntent(
                        productId = effect.productId,
                        packageName = context.packageName,
                    ),
                )
            }

            is ContributionContract.Effect.PurchaseContribution -> {
                effect.startPurchaseFlow(activity)
            }
        }
    }

    BackHandler {
        onBack()
    }

    Scaffold(
        modifier = modifier,
        topBar = {
            TopAppBarWithBackButton(
                title = stringResource(R.string.funding_googleplay_contribution_title),
                onBackClick = onBack,
            )
        },
    ) { innerPadding ->
        ContributionContent(
            state = state.value,
            onEvent = { dispatch(it) },
            contentPadding = innerPadding,
        )
    }
}

private const val SUBSCRIPTION_URL = "https://play.google.com/store/account/subscriptions"

private fun getManageSubscriptionIntent(
    productId: String,
    packageName: String,
): Intent {
    val uri = Uri.parse(SUBSCRIPTION_URL)
        .buildUpon()
        .appendQueryParameter("sku", productId)
        .appendQueryParameter("package", packageName)
        .build()

    return Intent(Intent.ACTION_VIEW, uri)
}"}

{"file_path":"/project/feature/account/server/settings/src/main/kotlin/app/k9mail/feature/account/server/settings/ui/common/TextFieldOutlinedPasswordBiometric.kt","content":"package app.k9mail.feature.account.server.settings.ui.common

import android.view.WindowManager
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.activity.compose.LocalActivity
import androidx.compose.runtime.Composable
import androidx.compose.runtime.DisposableEffect
import androidx.compose.runtime.getValue
import androidx.compose.runtime.mutableStateOf
import androidx.compose.runtime.saveable.rememberSaveable
import androidx.compose.runtime.setValue
import androidx.compose.ui.Modifier
import app.k9mail.core.ui.compose.designsystem.atom.textfield.TextFieldOutlinedPassword

/**
 * Variant of [TextFieldOutlinedPassword] that only allows the password to be unmasked after the user has authenticated
 * using [BiometricPrompt].
 *
 * Note: Due to limitations of [BiometricPrompt] this composable can only be used inside a [androidx.fragment.app.FragmentActivity].
 */
@Suppress("LongParameterList")
@Composable
fun TextFieldOutlinedPasswordBiometric(
    value: String,
    onValueChange: (String) -> Unit,
    authenticationTitle: String,
    authenticationSubtitle: String,
    needScreenLockMessage: String,
    onWarningChange: (CharSequence?) -> Unit,
    modifier: Modifier = Modifier,
    label: String? = null,
    isEnabled: Boolean = true,
    isReadOnly: Boolean = false,
    isRequired: Boolean = false,
    hasError: Boolean = false,
) {
    var isPasswordVisible by rememberSaveable { mutableStateOf(false) }
    var isAuthenticated by rememberSaveable { mutableStateOf(false) }
    var isAuthenticationRequired by rememberSaveable { mutableStateOf(true) }

    // If the entire password was removed, we allow the user to unmask the text field without requiring authentication.
    if (value.isEmpty()) {
        isAuthenticationRequired = false
    }

    val activity = LocalActivity.current as androidx.fragment.app.FragmentActivity

    TextFieldOutlinedPassword(
        value = value,
        onValueChange = onValueChange,
        modifier = modifier,
        label = label,
        isEnabled = isEnabled,
        isReadOnly = isReadOnly,
        isRequired = isRequired,
        hasError = hasError,
        isPasswordVisible = isPasswordVisible,
        onPasswordVisibilityToggleClicked = {
            if (!isAuthenticationRequired || isAuthenticated) {
                isPasswordVisible = !isPasswordVisible
                activity.setSecure(isPasswordVisible)
            } else {
                showBiometricPrompt(
                    activity,
                    authenticationTitle,
                    authenticationSubtitle,
                    needScreenLockMessage,
                    onAuthSuccess = {
                        isAuthenticated = true
                        isPasswordVisible = true
                        onWarningChange(null)
                        activity.setSecure(true)
                    },
                    onAuthError = onWarningChange,
                )
            }
        },
    )

    DisposableEffect(key1 = "secureWindow") {
        activity.setSecure(isPasswordVisible)

        onDispose {
            activity.setSecure(false)
        }
    }
}

private fun showBiometricPrompt(
    activity: androidx.fragment.app.FragmentActivity,
    title: String,
    subtitle: String,
    needScreenLockMessage: String,
    onAuthSuccess: () -> Unit,
    onAuthError: (CharSequence) -> Unit,
) {
    val authenticationCallback = object : BiometricPrompt.AuthenticationCallback() {
        override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
            onAuthSuccess()
        }

        override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
            if (errorCode == BiometricPrompt.ERROR_HW_NOT_PRESENT ||
                errorCode == BiometricPrompt.ERROR_NO_DEVICE_CREDENTIAL ||
                errorCode == BiometricPrompt.ERROR_NO_BIOMETRICS
            ) {
                onAuthError(needScreenLockMessage)
            } else if (errString.isNotEmpty()) {
                onAuthError(errString)
            }
        }
    }

    val promptInfo = BiometricPrompt.PromptInfo.Builder()
        .setAllowedAuthenticators(
            BiometricManager.Authenticators.BIOMETRIC_STRONG or
                BiometricManager.Authenticators.BIOMETRIC_WEAK or
                BiometricManager.Authenticators.DEVICE_CREDENTIAL,
        )
        .setTitle(title)
        .setSubtitle(subtitle)
        .build()

    BiometricPrompt(activity, authenticationCallback).authenticate(promptInfo)
}

private fun androidx.fragment.app.FragmentActivity.setSecure(secure: Boolean) {
    window.setFlags(if (secure) WindowManager.LayoutParams.FLAG_SECURE else 0, WindowManager.LayoutParams.FLAG_SECURE)
}"}

