 * Configures the unified inbox after an account has been added.
 */
class UnifiedInboxConfigurator(
    private val accountManager: AccountManager,
) {
    fun configureUnifiedInbox() {
        val accounts = accountManager.getAccounts()

        // Enable unified inbox only when going from 1 to 2 accounts
        // This ensures:
        // 1. Single account users can choose their preference
        // 2. Multi-account users get unified inbox enabled automatically
        // 3. Users who have disabled unified inbox after having multiple accounts won't have it re-enabled
        if (accounts.size == 2 && !K9.isShowUnifiedInbox) {
            // Check if the unified inbox setting has been explicitly set by the user
            // If it has never been enabled before, we auto-enable it when adding a second account
            val hasUnifiedInboxEverBeenEnabled = loadUnifiedInboxEnabledFromStorage()

            // If unified inbox has never been explicitly disabled by the user (default is false),
            // we enable it when there are 2 accounts
            if (!hasUnifiedInboxEverBeenEnabled) {
                K9.isShowUnifiedInbox = true
                K9.saveSettingsAsync()
            }
        }
    }

    /**
     * Checks if the unified inbox setting has been explicitly set to enabled in storage.
     * This helps us determine if the user has made a conscious choice to disable it.
     */
    private fun loadUnifiedInboxEnabledFromStorage(): Boolean {
        // We check the storage directly to see if the setting has been set to 'true' at any point.
        // The default for showUnifiedInbox is false, so if it's true in storage, the user
        // (or the initial setup) has enabled it before.
        // If it was never enabled in storage, we can safely enable it on the 2nd account.
        // If it was enabled then disabled, we respect the user's choice and don't re-enable it.
        return generalSettingsManager.storage.getBoolean("showUnifiedInbox", false)
    }

    companion object {
        // We need to inject this to access storage
        // This will be provided via constructor injection in the production code
        @JvmStatic
        private lateinit var generalSettingsManager: RealGeneralSettingsManager
    }
}"}

