{"file_path":"/project/legacy/core/src/test/java/com/fsck/k9/preferences/UnifiedInboxConfiguratorTest.kt","content":"package com.fsck.k9.preferences

import assertk.assertThat
import assertk.assertions.isFalse
import assertk.assertions.isTrue
import app.k9mail.legacy.account.Account
import com.fsck.k9.K9
import com.fsck.k9.K9RobolectricTest
import org.junit.Before
import org.junit.Test
import org.mockito.kotlin.mock
import org.mockito.kotlin.whenever

class UnifiedInboxConfiguratorTest : K9RobolectricTest() {

    private val accountManager = mock<app.k9mail.legacy.account.AccountManager>()
    private val unifiedInboxConfigurator = UnifiedInboxConfigurator(accountManager)

    @Before
    fun setup() {
        K9.isShowUnifiedInbox = false
    }

    @Test
    fun `configureUnifiedInbox enables unified inbox when going from 1 to 2 accounts`() {
        // Given: We have 1 account and unified inbox is disabled
        unifiedInboxConfigurator = UnifiedInboxConfigurator(accountManager)
        val account1 = createAccount("uuid1")
        whenever(accountManager.getAccounts()).thenReturn(listOf(account1))
        K9.isShowUnifiedInbox = false

        // When: A second account is added
        val account2 = createAccount("uuid2")
        whenever(accountManager.getAccounts()).thenReturn(listOf(account1, account2))

        // Then: Unified inbox should be enabled
        unifiedInboxConfigurator.configureUnifiedInbox()
        assertThat(K9.isShowUnifiedInbox).isTrue()
    }

    @Test
    fun `configureUnifiedInbox does not enable when adding a third account if unified inbox is already disabled`() {
        // Given: We have 2 accounts and unified inbox was previously enabled then disabled by user
        unifiedInboxConfigurator = UnifiedInboxConfigurator(accountManager)
        val account1 = createAccount("uuid1")
        val account2 = createAccount("uuid2")
        whenever(accountManager.getAccounts()).thenReturn(listOf(account1, account2))
        K9.isShowUnifiedInbox = false

        // When: A third account is added (user has chosen to disable unified inbox)
        val account3 = createAccount("uuid3")
        whenever(accountManager.getAccounts()).thenReturn(listOf(account1, account2, account3))

        // Then: Unified inbox should NOT be re-enabled (respect user preference)
        unifiedInboxConfigurator.configureUnifiedInbox()
        assertThat(K9.isShowUnifiedInbox).isFalse()
    }

    @Test
    fun `configureUnifiedInbox preserves existing unified inbox setting when adding more accounts`() {
        // Given: We have 2 accounts and unified inbox is already enabled
        unifiedInboxConfigurator = UnifiedInboxConfigurator(accountManager)
        val account1 = createAccount("uuid1")
        val account2 = createAccount("uuid2")
        whenever(accountManager.getAccounts()).thenReturn(listOf(account1, account2))
        K9.isShowUnifiedInbox = true

        // When: A third account is added
        val account3 = createAccount("uuid3")
        whenever(accountManager.getAccounts()).thenReturn(listOf(account1, account2, account3))

        // Then: Unified inbox should remain enabled
        unifiedInboxConfigurator.configureUnifiedInbox()
        assertThat(K9.isShowUnifiedInbox).isTrue()
    }

    @Test
    fun `configureUnifiedInbox does nothing with single account`() {
        // Given: We have 1 account and unified inbox is disabled
        unifiedInboxConfigurator = UnifiedInboxConfigurator(accountManager)
        val account1 = createAccount("uuid1")
        whenever(accountManager.getAccounts()).thenReturn(listOf(account1))
        K9.isShowUnifiedInbox = false

        // When: configureUnifiedInbox is called
        unifiedInboxConfigurator.configureUnifiedInbox()

        // Then: Unified inbox should stay disabled
        assertThat(K9.isShowUnifiedInbox).isFalse()
    }

    @Test
    fun `configureUnifiedInbox only enables once when going from 1 to 2 accounts`() {
        // Given: We have 1 account
        unifiedInboxConfigurator = UnifiedInboxConfigurator(accountManager)
        val account1 = createAccount("uuid1")
        whenever(accountManager.getAccounts()).thenReturn(listOf(account1))
        K9.isShowUnifiedInbox = false

        // When: We go from 1 to 2 accounts
        val account2 = createAccount("uuid2")
        whenever(accountManager.getAccounts()).thenReturn(listOf(account1, account2))
        unifiedInboxConfigurator.configureUnifiedInbox()

        // Then: Unified inbox should be enabled
        assertThat(K9.isShowUnifiedInbox).isTrue()

        // When: User disables unified inbox, then adds a third account
        K9.isShowUnifiedInbox = false
        val account3 = createAccount("uuid3")
        whenever(accountManager.getAccounts()).thenReturn(listOf(account1, account2, account3))

        // Then: Unified inbox should not be re-enabled
        K9.isShowUnifiedInbox = false // User explicitly disabled it
        unifiedInboxConfigurator.configureUnifiedInbox()
        assertThat(K9.isShowUnifiedInbox).isFalse()
    }

    private fun createAccount(uuid: String): Account {
        val account = Account(uuid, false)
        account.email = "test@example.com"
        return account
    }
}"}

