package com.fsck.k9.view

import assertk.assertThat
import assertk.assertions.isEmpty
import assertk.assertions.containsExactly
import com.fsck.k9.mail.Address
import org.junit.Test

class UserInputEmailAddressParserSlashValidationTest {
    private val parser = UserInputEmailAddressParser()

    @Test
    fun `email address ending with slash should be rejected`() {
        val addresses = parser.parse("xxx@gmail.com/")
        assertThat(addresses).isEmpty()
    }

    @Test
    fun `email address containing slash should be rejected`() {
        val addresses = parser.parse("user/name@gmail.com")
        assertThat(addresses).isEmpty()
    }

    @Test
    fun `valid email address without slash should be accepted`() {
        val addresses = parser.parse("xxx@gmail.com")
        assertThat(addresses).containsExactly(Address("xxx@gmail.com"))
    }

    @Test
    fun `email with multiple slashes should be rejected`() {
        val addresses = parser.parse("xxx@gmail.com/")
        assertThat(addresses).isEmpty()
    }

    @Test
    fun `email with query parameters should be rejected`() {
        val addresses = parser.parse("user@domain.com/path?param=value")
        assertThat(addresses).isEmpty()
    }
}"}

